int main()
{
    vector<int> numbers = {1, 3, -1, -3, 5, 3, 6, 7};
    int k = 3;
    deque<int> window; // stores INDICES, values decreasing front-to-back
    vector<int> result;

    for (int i = 0; i < numbers.size(); i++)
    {
        while (!window.empty() && numbers[window.back()] < numbers[i])
        {
            window.pop_back(); // remove smaller values from the back
        }
        window.push_back(i);

        if (window.front() <= i - k) // front index fell out of the window
        {
            window.pop_front();
        }

        if (i >= k - 1) // window is fully formed
        {
            result.push_back(numbers[window.front()]);
        }
    }

    for (int val : result)
    {
        cout << val << " ";
    }

    return 0;
}

