    int capacity;

    MyCircularDeque(int k) : capacity(k) {}

    bool insertFront(int value) { if ((int)data.size()==capacity) return false; data.push_front(value); return true; }
    bool insertLast(int value) { if ((int)data.size()==capacity) return false; data.push_back(value); return true; }
    bool deleteFront() { if (data.empty()) return false; data.pop_front(); return true; }
    bool deleteLast() { if (data.empty()) return false; data.pop_back(); return true; }
    int getFront() { return data.empty() ? -1 : data.front(); }
    int getRear() { return data.empty() ? -1 : data.back(); }
    bool isEmpty() { return data.empty(); }
    bool isFull() { return (int)data.size() == capacity; }
};

int main()
{
    MyCircularDeque dq(3);
