#include <iostream>
#include <vector>

using namespace std;

class MyCircularDeque {
public:
    vector<int> data;
    int capacity, head, count;

    MyCircularDeque(int k) : data(k), capacity(k), head(0), count(0) {}

    bool insertFront(int value)
    {
        if (count == capacity) return false;
        head = (head - 1 + capacity) % capacity;
        data[head] = value;
        count++;
        return true;
    }

    bool insertLast(int value)
    {
        if (count == capacity) return false;
        data[(head + count) % capacity] = value;
        count++;
        return true;
    }

    bool deleteFront()
    {
        if (count == 0) return false;
        head = (head + 1) % capacity;
        count--;
        return true;
    }

    bool deleteLast()
    {
        if (count == 0) return false;
        count--;
        return true;
    }

    int getFront() { return count == 0 ? -1 : data[head]; }
    int getRear() { return count == 0 ? -1 : data[(head + count - 1) % capacity]; }
    bool isEmpty() { return count == 0; }
    bool isFull() { return count == capacity; }
};

int main()
{
    MyCircularDeque dq(3);
    cout << dq.insertLast(1) << " " << dq.insertLast(2) << " " << dq.insertFront(3) << " ";
    cout << dq.isFull() << " " << dq.getRear() << " " << dq.isFull() << endl;

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

vector<int> maxSlidingWindow(vector<int> &nums, int k)
{
    vector<int> result;

    for (int i = 0; i + k <= (int)nums.size(); i++)
    {
        int windowMax = nums[i];
        for (int j = i; j < i + k; j++) windowMax = max(windowMax, nums[j]);
        result.push_back(windowMax);
    }

    return result;
}

int main()
{
    vector<int> nums = {1, 3, -1, -3, 5, 3, 6, 7};

    vector<int> result = maxSlidingWindow(nums, 3);
    for (int r : result) cout << r << " ";

    return 0;
}

